"""Sprite and enemy spawning pipeline for world scenes."""from __future__ import annotationsimport mathimport randomfrom pygame.math import Vector3from engine.textures.texture_utils import create_shadow_texturefrom game.config import (    GOBLIN_CHASE_GIVE_UP_RADIUS,    GOBLIN_CHASE_RADIUS,    GOBLIN_COUNT,    GOBLIN_MIN_SEPARATION,    GOBLIN_SPAWN_ATTEMPTS,    GOBLIN_SPAWN_CLEARANCE,    GOBLIN_SPAWN_TREE_RADIUS,)from game.world.objects import Goblinfrom game.world.road_pipeline import _build_roadsfrom game.world.world_spawner import spawn_world_spritesdef _build_roads_and_spawn_sprites(    scene, tree_count: int, grass_count: int, rock_count: int) -> None:    _build_roads(scene)    _spawn_trees(scene, tree_count)    _build_goblins(scene)    _spawn_grass(scene, grass_count)    _spawn_rocks(scene, rock_count)def _spawn_trees(scene, tree_count: int) -> None:    _spawn_sprite_layer(        scene,        label="trees",        count=tree_count,        textures=scene.tree_textures,        px_to_world=1.2,        x_off=(scene.ground_bounds[0] + scene.ground_bounds[1]) / 2 + 35,        z_off=(scene.ground_bounds[2] + scene.ground_bounds[3]) / 2 + 35,        max_spawn_x=(scene.ground_bounds[1] - scene.ground_bounds[0]) / 2 - 35,        max_spawn_z=(scene.ground_bounds[3] - scene.ground_bounds[2]) / 2 - 35,    )def _spawn_grass(scene, grass_count: int) -> None:    _spawn_sprite_layer(        scene,        label="grasses",        count=grass_count,        textures=scene.grasses_textures,        px_to_world=1.5,        x_off=(scene.ground_bounds[0] + scene.ground_bounds[1]) / 2,        z_off=(scene.ground_bounds[2] + scene.ground_bounds[3]) / 2,        max_spawn_x=(scene.ground_bounds[1] - scene.ground_bounds[0]) / 2,        max_spawn_z=(scene.ground_bounds[3] - scene.ground_bounds[2]) / 2,    )def _spawn_rocks(scene, rock_count: int) -> None:    _spawn_sprite_layer(        scene,        label="rocks",        count=rock_count,        textures=scene.rock_textures,        px_to_world=1.0,        x_off=(scene.ground_bounds[0] + scene.ground_bounds[1]) / 2,        z_off=(scene.ground_bounds[2] + scene.ground_bounds[3]) / 2,        max_spawn_x=(scene.ground_bounds[1] - scene.ground_bounds[0]) / 2,        max_spawn_z=(scene.ground_bounds[3] - scene.ground_bounds[2]) / 2,    )def _goblin_position_blocker(scene, *, block_roads: bool = True):    min_x, max_x, min_z, max_z = scene.ground_bounds    buildings = list(getattr(scene, "buildings", ()) or ())    def blocked(x: float, z: float, margin: float = 0.0) -> bool:        clearance = max(0.0, float(margin))        if (            x < min_x + clearance            or x > max_x - clearance            or z < min_z + clearance            or z > max_z - clearance        ):            return True        if block_roads and scene.is_on_road(x, z, margin=clearance):            return True        for building in buildings:            contains_point = getattr(building, "contains_point", None)            if not callable(contains_point):                continue            if contains_point(x, z, margin=clearance):                return True        return False    return blockeddef _random_goblin_spawn_near_tree(scene, rng: random.Random):    trees = list(getattr(scene, "trees", ()) or ())    min_x, max_x, min_z, max_z = scene.ground_bounds    if not trees:        x = rng.uniform(min_x, max_x)        z = rng.uniform(min_z, max_z)        return x, z    anchor = rng.choice(trees).position    angle = rng.uniform(0.0, math.tau)    radius = max(0.0, float(GOBLIN_SPAWN_TREE_RADIUS)) * math.sqrt(rng.random())    return (        float(anchor.x) + math.cos(angle) * radius,        float(anchor.z) + math.sin(angle) * radius,    )def _player_in_building_detector(scene):    def player_in_building() -> bool:        camera = getattr(scene, "camera", None)        position = getattr(camera, "position", None)        if position is None:            return False        x = float(position.x)        z = float(position.z)        for building in getattr(scene, "buildings", ()) or ():            contains_point = getattr(building, "contains_point", None)            if callable(contains_point) and contains_point(x, z, margin=0.0):                return True        return False    return player_in_buildingdef _build_goblins(scene) -> None:    for goblin in getattr(scene, "goblins", ()) or ():        try:            if goblin in scene.entities:                scene.entities.remove(goblin)            for sprite in goblin.get_sprites() or ():                if sprite in scene.sprite_items:                    scene.sprite_items.remove(sprite)        except Exception:            continue    goblin_tex = Goblin.texture_or_load(getattr(scene, "goblin_tex", None))    scene.goblin_tex = goblin_tex    front_frames = goblin_tex.get("front", ())    scene.goblins = []    count = max(0, int(getattr(scene, "goblin_count", GOBLIN_COUNT)))    if count <= 0 or not front_frames:        print("Spawned 0 goblins.")        return    shadow_texture = create_shadow_texture(        width_px=96,        height_px=96,        max_alpha=0.24,        inner_ratio=0.14,        outer_ratio=0.92,        falloff_exp=1.8,        pixelated=False,    )    rng = random.Random()    spawn_blocked = _goblin_position_blocker(scene, block_roads=True)    movement_blocked = _goblin_position_blocker(scene, block_roads=False)    clearance = max(        float(GOBLIN_SPAWN_CLEARANCE),        float(getattr(Goblin, "DEFAULT_HEIGHT", 0.0)) * 0.3,    )    min_separation_sq = max(0.0, float(GOBLIN_MIN_SEPARATION)) ** 2    max_attempts = max(1, int(GOBLIN_SPAWN_ATTEMPTS))    add_entity = getattr(scene, "add_entity", None)    player_in_building = _player_in_building_detector(scene)    chase_radius = float(getattr(scene, "goblin_chase_radius", GOBLIN_CHASE_RADIUS))    chase_give_up_radius = float(        getattr(scene, "goblin_chase_give_up_radius", GOBLIN_CHASE_GIVE_UP_RADIUS)    )    for _ in range(count):        spawn = None        for _attempt in range(max_attempts):            x, z = _random_goblin_spawn_near_tree(scene, rng)            if spawn_blocked(x, z, clearance):                continue            too_close = False            for other in scene.goblins:                dx = other.spawn_position.x - x                dz = other.spawn_position.z - z                if dx * dx + dz * dz < min_separation_sq:                    too_close = True                    break            if too_close:                continue            spawn = Vector3(x, scene.ground_height_at(x, z), z)            break        if spawn is None:            continue        try:            goblin = Goblin(                spawn,                texture=goblin_tex,                camera=scene.camera,                ground_height_at=scene.ground_height_at,                position_blocked=movement_blocked,                player_in_building=player_in_building,                chase_radius=chase_radius,                chase_give_up_radius=chase_give_up_radius,                shadow_texture=shadow_texture,                sound_keys=getattr(scene, "goblin_sound_keys", None),                rng=random.Random(rng.randrange(1 << 30)),            )        except (TypeError, ValueError, AttributeError):            continue        scene.goblins.append(goblin)        if callable(add_entity):            add_entity(goblin)        else:            scene.entities.append(goblin)            scene.sprite_items.extend(goblin.get_sprites())    print(f"Spawned {len(scene.goblins)} goblins.")    refresh_draw_entities = getattr(scene, "refresh_immediate_entities", None)    if callable(refresh_draw_entities):        refresh_draw_entities()def _spawn_sprite_layer(    scene,    *,    label: str,    count: int,    textures: list,    px_to_world: float,    x_off: float,    z_off: float,    max_spawn_x: float,    max_spawn_z: float,) -> None:    start_time = time.perf_counter()    sprites = spawn_world_sprites(        scene,        count=count,        textures=textures,        px_to_world=px_to_world,        camera=scene.camera,        x_off=x_off,        z_off=z_off,        max_spawn_x=max_spawn_x,        max_spawn_z=max_spawn_z,        avoid_roads=scene.roads,        avoid_areas=scene.buildings,    )    setattr(scene, label, sprites)    print(f"Spawned {len(sprites)} {label}.")    scene.log_timing(f"Spawn {label}", start_time, time.perf_counter())    scene.sprite_items.extend(sprites)